INSERT INTO questions (id,school_id,author_id,type,sub_strand,topic,bloom_level,difficulty,year_group,marks,question_text,explanation,is_active) VALUES
(715,1,1,'mcq','S2/SS1','Internet and WWW',1,'easy',1,1,'What does WWW stand for?','WWW stands for World Wide Web, a system of interlinked web pages.',1),
(716,1,1,'mcq','S2/SS1','Internet and WWW',1,'easy',1,1,'Which device is used to connect a computer to the internet?','A modem connects a computer to the internet.',1),
(717,1,1,'mcq','S2/SS1','Internet and WWW',2,'easy',1,1,'Which of the following is an example of a web browser?','Google Chrome is a web browser used to access websites.',1),
(718,1,1,'mcq','S2/SS1','Internet and WWW',2,'easy',1,1,'What is the main purpose of the internet?','The internet allows sharing of information globally.',1),
(719,1,1,'mcq','S2/SS1','Internet and WWW',1,'easy',1,1,'Which of the following is an internet service?','Email is a service provided over the internet.',1),
(720,1,1,'mcq','S2/SS1','Internet and WWW',1,'easy',1,1,'What does URL stand for?','URL stands for Uniform Resource Locator.',1),
(721,1,1,'mcq','S2/SS1','Internet and WWW',2,'easy',1,1,'Which part of a URL identifies the website name?','The domain name identifies the website.',1),
(722,1,1,'mcq','S2/SS1','Internet and WWW',2,'easy',1,1,'Which protocol is used to load web pages?','HTTP is used to transfer web pages.',1),
(723,1,1,'mcq','S2/SS1','Internet and WWW',1,'easy',1,1,'What is a web page?','A web page is a document on the internet.',1),
(724,1,1,'mcq','S2/SS1','Internet and WWW',2,'easy',1,1,'Which company developed the World Wide Web?','Tim Berners-Lee developed the WWW at CERN.',1),
(725,1,1,'mcq','S2/SS1','Internet and WWW',1,'easy',1,1,'What is an IP address?','An IP address uniquely identifies a device on a network.',1),
(726,1,1,'mcq','S2/SS1','Internet and WWW',2,'easy',1,1,'Which device directs data between networks?','A router directs data between networks.',1),
(727,1,1,'mcq','S2/SS1','Internet and WWW',1,'easy',1,1,'What does ISP stand for?','ISP stands for Internet Service Provider.',1),
(728,1,1,'mcq','S2/SS1','Internet and WWW',2,'easy',1,1,'Which of the following is an ISP in Ghana?','MTN provides internet services in Ghana.',1),
(729,1,1,'mcq','S2/SS1','Internet and WWW',1,'easy',1,1,'What is email used for?','Email is used for sending messages electronically.',1),
(730,1,1,'mcq','S2/SS1','Internet and WWW',2,'easy',1,1,'Which symbol is used in email addresses?','The @ symbol is used in email addresses.',1),
(731,1,1,'mcq','S2/SS1','Internet and WWW',1,'easy',1,1,'What is a search engine?','A search engine helps find information online.',1),
(732,1,1,'mcq','S2/SS1','Internet and WWW',2,'easy',1,1,'Which of the following is a search engine?','Google is a search engine.',1),
(733,1,1,'mcq','S2/SS1','Internet and WWW',1,'easy',1,1,'What is downloading?','Downloading is receiving data from the internet.',1),
(734,1,1,'mcq','S2/SS1','Internet and WWW',2,'easy',1,1,'What is uploading?','Uploading is sending data to the internet.',1);
