INSERT INTO questions (id,school_id,author_id,type,sub_strand,topic,bloom_level,difficulty,year_group,marks,question_text,explanation,is_active) VALUES
(735,1,1,'mcq','S2/SS1','Internet and WWW',2,'easy',1,1,'Which device converts digital signals to analog signals for internet transmission?','A modem converts digital signals to analog signals and vice versa.',1),
(736,1,1,'mcq','S2/SS1','Internet and WWW',2,'easy',1,1,'What is the main function of a browser?','A browser retrieves and displays web pages.',1),
(737,1,1,'mcq','S2/SS1','Internet and WWW',2,'easy',1,1,'Which of the following is used to find information on the internet?','Search engines help users locate information online.',1),
(738,1,1,'mcq','S2/SS1','Internet and WWW',1,'easy',1,1,'What is a homepage?','A homepage is the first page of a website.',1),
(739,1,1,'mcq','S2/SS1','Internet and WWW',2,'easy',1,1,'Which protocol is commonly used for secure web browsing?','HTTPS encrypts communication between browser and server.',1),
(740,1,1,'mcq','S2/SS1','Internet and WWW',1,'easy',1,1,'What is the internet?','The internet is a global network of interconnected computers.',1),
(741,1,1,'mcq','S2/SS1','Internet and WWW',2,'medium',1,1,'Which of the following best describes a hyperlink?','A hyperlink connects one web page or resource to another.',1),
(742,1,1,'mcq','S2/SS1','Internet and WWW',2,'medium',1,1,'Which component of a URL comes first?','The protocol appears first in a URL.',1),
(743,1,1,'mcq','S2/SS1','Internet and WWW',2,'medium',1,1,'Which internet service allows real-time text communication?','Instant messaging supports real-time text communication.',1),
(744,1,1,'mcq','S2/SS1','Internet and WWW',2,'medium',1,1,'What does DNS do on the internet?','DNS translates domain names into IP addresses.',1),
(745,1,1,'mcq','S2/SS1','Internet and WWW',2,'medium',1,1,'Which of the following is an example of cloud storage?','Google Drive provides cloud storage.',1),
(746,1,1,'mcq','S2/SS1','Internet and WWW',2,'medium',1,1,'Which internet service is used to transfer files?','FTP is used for file transfer.',1),
(747,1,1,'mcq','S2/SS1','Internet and WWW',3,'medium',1,1,'Why is an IP address important on the internet?','It identifies the source and destination of data.',1),
(748,1,1,'mcq','S2/SS1','Internet and WWW',3,'medium',1,1,'What happens when a user clicks a web link?','The browser requests the linked resource from a server.',1),
(749,1,1,'mcq','S2/SS1','Internet and WWW',3,'medium',1,1,'Which device connects multiple computers within a network?','A switch connects devices within a local network.',1),
(750,1,1,'mcq','S2/SS1','Internet and WWW',3,'medium',1,1,'What is bandwidth?','Bandwidth is the amount of data that can be transmitted in a given time.',1),
(751,1,1,'mcq','S2/SS1','Internet and WWW',3,'medium',1,1,'Which of the following affects internet speed most directly?','Bandwidth has a major effect on internet speed.',1),
(752,1,1,'mcq','S2/SS1','Internet and WWW',3,'medium',1,1,'What does a server do on the internet?','A server stores and provides resources to clients.',1),
(753,1,1,'mcq','S2/SS1','Internet and WWW',3,'medium',1,1,'Which internet service allows voice communication online?','VoIP allows voice calls over the internet.',1),
(754,1,1,'mcq','S2/SS1','Internet and WWW',3,'medium',1,1,'Which of the following best explains uploading?','Uploading means transferring data from a local device to a remote system.',1);
