INSERT INTO questions (id,school_id,author_id,type,sub_strand,topic,bloom_level,difficulty,year_group,marks,question_text,explanation,is_active) VALUES
(755,1,1,'mcq','S2/SS1','Internet and WWW',2,'medium',1,1,'Which of the following best describes a web server?','A web server stores and delivers web pages to users.',1),
(756,1,1,'mcq','S2/SS1','Internet and WWW',2,'medium',1,1,'What is the function of HTTPS?','HTTPS provides secure communication over a network.',1),
(757,1,1,'mcq','S2/SS1','Internet and WWW',2,'medium',1,1,'Which of the following is a domain name?','A domain name is a human-readable website address.',1),
(758,1,1,'mcq','S2/SS1','Internet and WWW',3,'medium',1,1,'Why are cookies used in web browsing?','Cookies store user preferences and session data.',1),
(759,1,1,'mcq','S2/SS1','Internet and WWW',3,'medium',1,1,'What is streaming?','Streaming allows media to be played while it is being downloaded.',1),
(760,1,1,'mcq','S2/SS1','Internet and WWW',3,'medium',1,1,'Which of the following best explains packet switching?','Packet switching breaks data into smaller packets for transmission.',1),
(761,1,1,'mcq','S2/SS1','Internet and WWW',3,'medium',1,1,'What is latency in networking?','Latency is the delay in data transmission.',1),
(762,1,1,'mcq','S2/SS1','Internet and WWW',3,'medium',1,1,'Which of the following is used to uniquely identify a web page?','A URL uniquely identifies a web resource.',1),
(763,1,1,'mcq','S2/SS1','Internet and WWW',3,'medium',1,1,'Which protocol is used to send emails?','SMTP is used to send emails.',1),
(764,1,1,'mcq','S2/SS1','Internet and WWW',3,'medium',1,1,'Which protocol is used to receive emails?','POP3 or IMAP is used to receive emails.',1),
(765,1,1,'mcq','S2/SS1','Internet and WWW',4,'hard',1,1,'Why is DNS important in internet communication?','DNS simplifies access by converting names to IP addresses.',1),
(766,1,1,'mcq','S2/SS1','Internet and WWW',4,'hard',1,1,'What role does a router play in data transmission?','A router directs packets between networks.',1),
(767,1,1,'mcq','S2/SS1','Internet and WWW',4,'hard',1,1,'How does a browser interpret web pages?','Browsers use HTML to render web pages.',1),
(768,1,1,'mcq','S2/SS1','Internet and WWW',4,'hard',1,1,'Why is HTTPS preferred over HTTP?','HTTPS encrypts data for security.',1),
(769,1,1,'mcq','S2/SS1','Internet and WWW',4,'hard',1,1,'Which of the following best describes bandwidth usage?','Bandwidth usage refers to how much data is transmitted over a network.',1),
(770,1,1,'mcq','S2/SS1','Internet and WWW',4,'hard',1,1,'What is the purpose of an IP address in routing?','It ensures data reaches the correct destination.',1),
(771,1,1,'mcq','S2/SS1','Internet and WWW',4,'hard',1,1,'Which of the following best explains cloud computing?','Cloud computing provides services over the internet.',1),
(772,1,1,'mcq','S2/SS1','Internet and WWW',4,'hard',1,1,'Why is packet loss a problem in networking?','Packet loss leads to incomplete data transmission.',1),
(773,1,1,'mcq','S2/SS1','Internet and WWW',4,'hard',1,1,'Which of the following best describes peer-to-peer networking?','Devices share resources directly without a central server.',1),
(774,1,1,'mcq','S2/SS1','Internet and WWW',4,'hard',1,1,'What is the main function of a firewall?','A firewall protects a network by filtering traffic.',1);
