INSERT INTO questions (id,school_id,author_id,type,sub_strand,topic,bloom_level,difficulty,year_group,marks,question_text,explanation,is_active) VALUES
(775,1,1,'mcq','S2/SS1','Internet and WWW',2,'medium',1,1,'Which of the following is an example of a web client?','A web browser acts as a client requesting services from servers.',1),
(776,1,1,'mcq','S2/SS1','Internet and WWW',2,'medium',1,1,'What is the primary purpose of FTP?','FTP is used for transferring files between computers over a network.',1),
(777,1,1,'mcq','S2/SS1','Internet and WWW',2,'medium',1,1,'Which of the following best describes HTML?','HTML is used to structure web pages.',1),
(778,1,1,'mcq','S2/SS1','Internet and WWW',3,'medium',1,1,'What happens when a DNS server is unavailable?','The browser cannot resolve domain names into IP addresses.',1),
(779,1,1,'mcq','S2/SS1','Internet and WWW',3,'medium',1,1,'Which factor can cause slow internet speed?','High latency can slow down internet performance.',1),
(780,1,1,'mcq','S2/SS1','Internet and WWW',3,'medium',1,1,'What is the purpose of a proxy server?','A proxy server acts as an intermediary between client and server.',1),
(781,1,1,'mcq','S2/SS1','Internet and WWW',3,'medium',1,1,'Which of the following best explains web hosting?','Web hosting stores websites on servers for access over the internet.',1),
(782,1,1,'mcq','S2/SS1','Internet and WWW',3,'medium',1,1,'What does caching do in web browsing?','Caching stores frequently accessed data to improve speed.',1),
(783,1,1,'mcq','S2/SS1','Internet and WWW',3,'medium',1,1,'Which internet service allows video conferencing?','Video conferencing tools enable real-time video communication.',1),
(784,1,1,'mcq','S2/SS1','Internet and WWW',3,'medium',1,1,'What is the main function of a network protocol?','Protocols define rules for communication between devices.',1),
(785,1,1,'mcq','S2/SS1','Internet and WWW',4,'hard',1,1,'Why is packet switching more efficient than circuit switching?','It allows multiple transmissions over the same network.',1),
(786,1,1,'mcq','S2/SS1','Internet and WWW',4,'hard',1,1,'How does encryption improve internet security?','Encryption protects data from unauthorized access.',1),
(787,1,1,'mcq','S2/SS1','Internet and WWW',4,'hard',1,1,'What role does TCP play in networking?','TCP ensures reliable data transmission.',1),
(788,1,1,'mcq','S2/SS1','Internet and WWW',4,'hard',1,1,'What is the function of UDP protocol?','UDP provides faster but less reliable data transmission.',1),
(789,1,1,'mcq','S2/SS1','Internet and WWW',4,'hard',1,1,'Why is redundancy important in network design?','Redundancy ensures network reliability during failures.',1),
(790,1,1,'mcq','S2/SS1','Internet and WWW',4,'hard',1,1,'Which of the following best explains load balancing?','Load balancing distributes traffic across servers.',1),
(791,1,1,'mcq','S2/SS1','Internet and WWW',4,'hard',1,1,'What is the purpose of NAT in networking?','NAT translates private IP addresses to public ones.',1),
(792,1,1,'mcq','S2/SS1','Internet and WWW',4,'hard',1,1,'Why is IPv6 needed?','IPv6 provides a larger address space than IPv4.',1),
(793,1,1,'mcq','S2/SS1','Internet and WWW',4,'hard',1,1,'What is the function of a CDN?','A CDN delivers content faster by using distributed servers.',1),
(794,1,1,'mcq','S2/SS1','Internet and WWW',4,'hard',1,1,'Why are firewalls important in network security?','Firewalls prevent unauthorized access to networks.',1);
