(815,1,1,'mcq','S2/SS1','Internet and WWW',1,'easy',1,1,'Which part of a URL indicates the type of connection?','The protocol (e.g., http or https) indicates the connection type.',1),
(816,1,1,'mcq','S2/SS1','Internet and WWW',1,'easy',1,1,'What is the main purpose of a search engine?','It helps users locate information on the internet.',1),
(817,1,1,'mcq','S2/SS1','Internet and WWW',1,'easy',1,1,'Which of the following allows users to watch videos online?','Streaming services allow users to watch videos online.',1),
(818,1,1,'mcq','S2/SS1','Internet and WWW',1,'easy',1,1,'What is a hyperlink mainly used for?','It is used to navigate between web pages.',1),
(819,1,1,'mcq','S2/SS1','Internet and WWW',1,'easy',1,1,'Which device helps share internet connection among multiple computers?','A router distributes internet connection to multiple devices.',1),
(820,1,1,'mcq','S2/SS1','Internet and WWW',1,'easy',1,1,'Which of the following is used to access websites?','A browser is used to access websites.',1),
(821,1,1,'mcq','S2/SS1','Internet and WWW',1,'easy',1,1,'What is the function of the address bar in a browser?','It is used to enter website addresses.',1),
(822,1,1,'mcq','S2/SS1','Internet and WWW',1,'easy',1,1,'Which of the following represents a web address?','A URL is a web address.',1),
(823,1,1,'mcq','S2/SS1','Internet and WWW',1,'easy',1,1,'Which of the following is an example of online communication?','Chatting is a form of online communication.',1),
(824,1,1,'mcq','S2/SS1','Internet and WWW',1,'easy',1,1,'What is the purpose of bookmarks in a browser?','Bookmarks save frequently visited websites.',1),
(825,1,1,'mcq','S2/SS1','Internet and WWW',1,'easy',1,1,'Which internet activity involves sending files to another computer?','Uploading sends files to another system.',1),
(826,1,1,'mcq','S2/SS1','Internet and WWW',1,'easy',1,1,'Which of the following is used to locate information quickly online?','Search engines help locate information quickly.',1),
(827,1,1,'mcq','S2/SS1','Internet and WWW',1,'easy',1,1,'What is the main function of a webpage link?','It connects one page to another.',1),
(828,1,1,'mcq','S2/SS1','Internet and WWW',1,'easy',1,1,'Which device is used to receive internet signals wirelessly?','A Wi-Fi adapter receives wireless signals.',1),
(829,1,1,'mcq','S2/SS1','Internet and WWW',1,'easy',1,1,'What is the purpose of a web browser tab?','Tabs allow multiple web pages to be open at once.',1),
(830,1,1,'mcq','S2/SS1','Internet and WWW',1,'easy',1,1,'Which of the following is used to share information globally?','The internet allows global sharing of information.',1),
(831,1,1,'mcq','S2/SS1','Internet and WWW',1,'easy',1,1,'Which activity involves retrieving files from the internet?','Downloading retrieves files from the internet.',1),
(832,1,1,'mcq','S2/SS1','Internet and WWW',1,'easy',1,1,'What is the purpose of refresh button in a browser?','It reloads the current webpage.',1),
(833,1,1,'mcq','S2/SS1','Internet and WWW',1,'easy',1,1,'Which of the following enables communication over long distances?','The internet enables long-distance communication.',1),
(834,1,1,'mcq','S2/SS1','Internet and WWW',1,'easy',1,1,'Which tool helps users find websites based on keywords?','Search engines use keywords to find websites.',1);
