(845,1,1,'mcq','S2/SS1','Internet and WWW',1,'easy',1,1,'Which of the following is used to send messages instantly over the internet?','Chat applications send instant messages.',1),
(846,1,1,'mcq','S2/SS1','Internet and WWW',1,'easy',1,1,'What is the function of a scroll bar on a webpage?','It allows users to move up and down the page.',1),
(847,1,1,'mcq','S2/SS1','Internet and WWW',1,'easy',1,1,'Which of the following is a popular use of the internet?','Online learning is a common use of the internet.',1),
(848,1,1,'mcq','S2/SS1','Internet and WWW',1,'easy',1,1,'What is the main purpose of a login page?','It allows users to access secure areas of a website.',1),
