(851,1,1,'mcq','S2/SS1','Internet and WWW',1,'easy',1,1,'Which of the following allows users to share photos online?','Social media platforms allow photo sharing.',1),
(852,1,1,'mcq','S2/SS1','Internet and WWW',1,'easy',1,1,'What is the main purpose of a password on a website?','A password protects user accounts.',1),
(853,1,1,'mcq','S2/SS1','Internet and WWW',1,'easy',1,1,'Which of the following is used to view online videos?','A browser or app can be used to view videos online.',1),
(854,1,1,'mcq','S2/SS1','Internet and WWW',1,'easy',1,1,'What is the purpose of the logout button?','It signs the user out of an account.',1);
