INSERT INTO questions (id,school_id,author_id,type,sub_strand,topic,bloom_level,difficulty,year_group,marks,question_text,explanation,is_active) VALUES
(875,1,1,'mcq','S2/SS1','Internet and WWW',2,'medium',1,1,'Why is a web browser considered a client in networking?','Because it requests services from web servers.',1),
(876,1,1,'mcq','S2/SS1','Internet and WWW',2,'medium',1,1,'What is the relationship between a domain name and IP address?','A domain name maps to an IP address via DNS.',1),
(877,1,1,'mcq','S2/SS1','Internet and WWW',3,'medium',1,1,'Why do websites use cookies?','To store user session and preferences.',1),
(878,1,1,'mcq','S2/SS1','Internet and WWW',3,'medium',1,1,'What happens when you enter a URL in a browser?','The browser sends a request to a web server.',1),
(879,1,1,'mcq','S2/SS1','Internet and WWW',3,'medium',1,1,'Why is HTTPS more secure than HTTP?','Because it encrypts transmitted data.',1),
(880,1,1,'mcq','S2/SS1','Internet and WWW',3,'medium',1,1,'What role does a router play in internet communication?','It forwards data packets between networks.',1),
(881,1,1,'mcq','S2/SS1','Internet and WWW',3,'medium',1,1,'Why is bandwidth important for internet performance?','It determines data transfer capacity.',1),
(882,1,1,'mcq','S2/SS1','Internet and WWW',3,'medium',1,1,'What is the function of DNS caching?','It speeds up domain name resolution.',1),
(883,1,1,'mcq','S2/SS1','Internet and WWW',3,'medium',1,1,'Why is an IP address necessary in networking?','It uniquely identifies devices on a network.',1),
(884,1,1,'mcq','S2/SS1','Internet and WWW',3,'medium',1,1,'What happens during a packet loss?','Some data fails to reach its destination.',1),
(885,1,1,'mcq','S2/SS1','Internet and WWW',3,'medium',1,1,'Why is latency important in online gaming?','It affects response delay between actions.',1),
(886,1,1,'mcq','S2/SS1','Internet and WWW',3,'medium',1,1,'What is the function of a proxy server?','It acts as an intermediary between user and internet.',1),
(887,1,1,'mcq','S2/SS1','Internet and WWW',3,'medium',1,1,'Why is a firewall used in networks?','To block unauthorized access.',1),
(888,1,1,'mcq','S2/SS1','Internet and WWW',3,'medium',1,1,'What is the function of a switch in a LAN?','It connects devices within a local network.',1),
(889,1,1,'mcq','S2/SS1','Internet and WWW',3,'medium',1,1,'Why is cloud storage widely used?','It allows remote access to files.',1),
(890,1,1,'mcq','S2/SS1','Internet and WWW',3,'medium',1,1,'What is the function of a server in a network?','It provides resources to clients.',1),
(891,1,1,'mcq','S2/SS1','Internet and WWW',3,'medium',1,1,'Why is packet switching used in the internet?','It efficiently transmits data across networks.',1),
(892,1,1,'mcq','S2/SS1','Internet and WWW',3,'medium',1,1,'What is the role of TCP in data transmission?','It ensures reliable delivery of data packets.',1),
(893,1,1,'mcq','S2/SS1','Internet and WWW',3,'medium',1,1,'Why is UDP used for some applications?','It allows faster but less reliable transmission.',1),
(894,1,1,'mcq','S2/SS1','Internet and WWW',3,'medium',1,1,'What is the purpose of NAT in networking?','It translates private IPs to public IPs.',1),
(895,1,1,'mcq','S2/SS1','Internet and WWW',3,'medium',1,1,'Why is IPv6 important?','It provides more IP addresses than IPv4.',1),
(896,1,1,'mcq','S2/SS1','Internet and WWW',3,'medium',1,1,'What is the function of a gateway?','It connects different networks.',1),
(897,1,1,'mcq','S2/SS1','Internet and WWW',3,'medium',1,1,'Why is a MAC address important?','It uniquely identifies network devices.',1),
(898,1,1,'mcq','S2/SS1','Internet and WWW',3,'medium',1,1,'What is the function of HTTP?','It transfers web pages over the internet.',1),
(899,1,1,'mcq','S2/SS1','Internet and WWW',3,'medium',1,1,'Why is a DNS server needed?','It converts domain names to IP addresses.',1),
(900,1,1,'mcq','S2/SS1','Internet and WWW',3,'medium',1,1,'What is the role of a modem?','It converts digital and analog signals.',1),
(901,1,1,'mcq','S2/SS1','Internet and WWW',3,'medium',1,1,'Why is streaming preferred over downloading?','It allows immediate playback of media.',1),
(902,1,1,'mcq','S2/SS1','Internet and WWW',3,'medium',1,1,'What is the role of email servers?','They send and receive emails.',1),
(903,1,1,'mcq','S2/SS1','Internet and WWW',3,'medium',1,1,'Why is authentication important online?','It verifies user identity.',1),
(904,1,1,'mcq','S2/SS1','Internet and WWW',3,'medium',1,1,'What is the function of encryption?','It secures data during transmission.',1),
(905,1,1,'mcq','S2/SS1','Internet and WWW',3,'medium',1,1,'Why is network topology important?','It defines how devices are arranged.',1),
(906,1,1,'mcq','S2/SS1','Internet and WWW',3,'medium',1,1,'What is the role of HTTP cookies?','They store user session information.',1),
(907,1,1,'mcq','S2/SS1','Internet and WWW',3,'medium',1,1,'Why is a URL structure important?','It helps locate resources on the web.',1),
(908,1,1,'mcq','S2/SS1','Internet and WWW',3,'medium',1,1,'What is the function of a web host?','It stores websites on servers.',1),
(909,1,1,'mcq','S2/SS1','Internet and WWW',3,'medium',1,1,'Why is redundancy used in networks?','To prevent system failure.',1),
(910,1,1,'mcq','S2/SS1','Internet and WWW',3,'medium',1,1,'What is the role of load balancing?','It distributes network traffic evenly.',1),
(911,1,1,'mcq','S2/SS1','Internet and WWW',3,'medium',1,1,'Why is VoIP useful?','It enables voice communication over the internet.',1),
(912,1,1,'mcq','S2/SS1','Internet and WWW',3,'medium',1,1,'What is the function of a VPN?','It provides secure internet access.',1),
(913,1,1,'mcq','S2/SS1','Internet and WWW',3,'medium',1,1,'Why is packet fragmentation used?','To fit data into network size limits.',1),
(914,1,1,'mcq','S2/SS1','Internet and WWW',3,'medium',1,1,'What is the role of ICMP?','It is used for error reporting and diagnostics.',1);
