INSERT INTO questions (id,school_id,author_id,type,sub_strand,topic,bloom_level,difficulty,year_group,marks,question_text,explanation,is_active) VALUES
(915,1,1,'mcq','S2/SS1','Transmission Media',2,'medium',1,1,'How are transmission media broadly classified?','They are classified into guided and unguided media.',1),
(916,1,1,'mcq','S2/SS1','Transmission Media',2,'medium',1,1,'What is the key feature of guided transmission media?','Signals travel through a physical path.',1),
(917,1,1,'mcq','S2/SS1','Transmission Media',2,'medium',1,1,'Which type of cable uses light signals for data transmission?','Fibre-optic cables use light signals.',1),
(918,1,1,'mcq','S2/SS1','Transmission Media',2,'medium',1,1,'Why is twisted pair cable commonly used in LANs?','It is cheap and easy to install.',1),
(919,1,1,'mcq','S2/SS1','Transmission Media',2,'medium',1,1,'What is the main advantage of coaxial cable over twisted pair?','It has better shielding against interference.',1),
(920,1,1,'mcq','S2/SS1','Transmission Media',2,'medium',1,1,'Why is fibre-optic cable preferred for long-distance communication?','It has very low signal loss.',1),
(921,1,1,'mcq','S2/SS1','Transmission Media',2,'medium',1,1,'What is the structure of a twisted pair cable?','It consists of two insulated wires twisted together.',1),
(922,1,1,'mcq','S2/SS1','Transmission Media',2,'medium',1,1,'What is the purpose of shielding in coaxial cables?','To reduce electromagnetic interference.',1),
(923,1,1,'mcq','S2/SS1','Transmission Media',2,'medium',1,1,'What makes fibre-optic cables immune to electromagnetic interference?','They use light instead of electrical signals.',1),
(924,1,1,'mcq','S2/SS1','Transmission Media',2,'medium',1,1,'Which guided medium offers the highest data transmission speed?','Fibre-optic cable offers the highest speed.',1),
(925,1,1,'mcq','S2/SS1','Transmission Media',2,'medium',1,1,'Why are twisted pair cables twisted?','To reduce interference between wires.',1),
(926,1,1,'mcq','S2/SS1','Transmission Media',2,'medium',1,1,'Which cable type is most affected by noise?','Twisted pair is more affected compared to others.',1),
(927,1,1,'mcq','S2/SS1','Transmission Media',2,'medium',1,1,'What is a key limitation of coaxial cable?','It is bulkier and harder to install.',1),
(928,1,1,'mcq','S2/SS1','Transmission Media',2,'medium',1,1,'Why is fibre-optic cable more secure?','It is difficult to tap without detection.',1),
(929,1,1,'mcq','S2/SS1','Transmission Media',2,'medium',1,1,'What is unguided transmission media?','Data is transmitted through air or space.',1),
(930,1,1,'mcq','S2/SS1','Transmission Media',2,'medium',1,1,'Which technology uses radio waves for short-range communication?','Bluetooth uses radio waves.',1),
(931,1,1,'mcq','S2/SS1','Transmission Media',2,'medium',1,1,'What is the range of NFC communication?','It works over very short distances.',1),
(932,1,1,'mcq','S2/SS1','Transmission Media',2,'medium',1,1,'Which wireless technology uses infrared signals?','IR communication uses infrared light.',1),
(933,1,1,'mcq','S2/SS1','Transmission Media',2,'medium',1,1,'What is the main advantage of Wi-Fi?','It allows wireless internet access.',1),
(934,1,1,'mcq','S2/SS1','Transmission Media',2,'medium',1,1,'Which technology is used in mobile phone networks?','Cellular networks are used.',1),
(935,1,1,'mcq','S2/SS1','Transmission Media',2,'medium',1,1,'What is the role of satellites in communication?','They relay signals over long distances.',1),
(936,1,1,'mcq','S2/SS1','Transmission Media',2,'medium',1,1,'Why is Bluetooth suitable for personal devices?','It consumes low power.',1),
(937,1,1,'mcq','S2/SS1','Transmission Media',2,'medium',1,1,'Why is NFC used for contactless payments?','It works at very close range securely.',1),
(938,1,1,'mcq','S2/SS1','Transmission Media',2,'medium',1,1,'What is a limitation of infrared communication?','It requires line-of-sight.',1),
(939,1,1,'mcq','S2/SS1','Transmission Media',2,'medium',1,1,'Why is Wi-Fi widely used in homes and schools?','It provides easy wireless connectivity.',1),
(940,1,1,'mcq','S2/SS1','Transmission Media',2,'medium',1,1,'What is the advantage of cellular networks?','They provide wide coverage.',1),
(941,1,1,'mcq','S2/SS1','Transmission Media',2,'medium',1,1,'Why are satellites used in remote areas?','They provide coverage where cables cannot reach.',1),
(942,1,1,'mcq','S2/SS1','Transmission Media',2,'medium',1,1,'What distinguishes guided from unguided media?','Guided uses cables while unguided uses air.',1),
(943,1,1,'mcq','S2/SS1','Transmission Media',2,'medium',1,1,'Which medium is more affected by physical damage?','Guided media is more affected.',1),
(944,1,1,'mcq','S2/SS1','Transmission Media',2,'medium',1,1,'Which medium is more flexible in installation?','Unguided media is more flexible.',1),
(945,1,1,'mcq','S2/SS1','Transmission Media',2,'medium',1,1,'Why is fibre-optic preferred over copper cables?','It offers higher speed and lower loss.',1),
(946,1,1,'mcq','S2/SS1','Transmission Media',2,'medium',1,1,'Which guided medium is cheapest?','Twisted pair is the cheapest.',1),
(947,1,1,'mcq','S2/SS1','Transmission Media',2,'medium',1,1,'Which unguided medium uses electromagnetic waves?','All wireless media use electromagnetic waves.',1),
(948,1,1,'mcq','S2/SS1','Transmission Media',2,'medium',1,1,'Why is coaxial cable less common today?','It is replaced by faster technologies.',1),
(949,1,1,'mcq','S2/SS1','Transmission Media',2,'medium',1,1,'What is the main challenge of wireless communication?','It is prone to interference.',1),
(950,1,1,'mcq','S2/SS1','Transmission Media',2,'medium',1,1,'Which medium supports highest bandwidth?','Fibre-optic supports highest bandwidth.',1),
(951,1,1,'mcq','S2/SS1','Transmission Media',2,'medium',1,1,'Why is guided media considered more secure?','Signals are confined within cables.',1),
(952,1,1,'mcq','S2/SS1','Transmission Media',2,'medium',1,1,'Which wireless technology is used for internet hotspots?','Wi-Fi is used for hotspots.',1),
(953,1,1,'mcq','S2/SS1','Transmission Media',2,'medium',1,1,'Which technology is best for global communication?','Satellite communication enables global coverage.',1),
(954,1,1,'mcq','S2/SS1','Transmission Media',2,'medium',1,1,'Why is unguided media easier to deploy?','It does not require physical cables.',1);
