INSERT INTO questions (id,school_id,author_id,type,sub_strand,topic,bloom_level,difficulty,year_group,marks,question_text,explanation,is_active) VALUES
(955,1,1,'mcq','S2/SS1','Transmission Media',4,'hard',1,1,'Which transmission medium is most suitable for high-speed backbone networks over long distances?','Fibre-optic provides highest speed and minimal loss over long distances.',1),
(956,1,1,'mcq','S2/SS1','Transmission Media',4,'hard',1,1,'Why is twisted pair cable more prone to interference compared to coaxial cable?','It lacks strong shielding.',1),
(957,1,1,'mcq','S2/SS1','Transmission Media',4,'hard',1,1,'In which scenario would fibre-optic cable be preferred over wireless communication?','When high security and speed are required.',1),
(958,1,1,'mcq','S2/SS1','Transmission Media',4,'hard',1,1,'Why is satellite communication associated with higher latency?','Signals travel long distances to space and back.',1),
(959,1,1,'mcq','S2/SS1','Transmission Media',4,'hard',1,1,'Which factor makes coaxial cable more reliable than twisted pair?','Better shielding reduces signal interference.',1),
(960,1,1,'mcq','S2/SS1','Transmission Media',4,'hard',1,1,'Why is Wi-Fi considered less secure than wired connections?','Signals can be intercepted over the air.',1),
(961,1,1,'mcq','S2/SS1','Transmission Media',4,'hard',1,1,'Which technology is best for secure short-range transactions like mobile payments?','NFC is secure due to very short range.',1),
(962,1,1,'mcq','S2/SS1','Transmission Media',4,'hard',1,1,'Why is fibre-optic cable not affected by electromagnetic interference?','It transmits data using light instead of electricity.',1),
(963,1,1,'mcq','S2/SS1','Transmission Media',4,'hard',1,1,'In a noisy industrial environment, which medium is most suitable?','Fibre-optic is immune to noise.',1),
(964,1,1,'mcq','S2/SS1','Transmission Media',4,'hard',1,1,'Which guided medium provides a balance between cost and performance for medium distances?','Coaxial cable offers moderate cost and shielding.',1),
(965,1,1,'mcq','S2/SS1','Transmission Media',4,'hard',1,1,'Why is Bluetooth unsuitable for long-distance communication?','It has limited transmission range.',1),
(966,1,1,'mcq','S2/SS1','Transmission Media',4,'hard',1,1,'Which factor limits infrared communication?','It requires direct line-of-sight.',1),
(967,1,1,'mcq','S2/SS1','Transmission Media',4,'hard',1,1,'Why is cellular communication more scalable than Wi-Fi?','It uses a network of base stations covering large areas.',1),
(968,1,1,'mcq','S2/SS1','Transmission Media',4,'hard',1,1,'Which medium would be most appropriate for connecting continents?','Submarine fibre-optic cables are used globally.',1),
(969,1,1,'mcq','S2/SS1','Transmission Media',4,'hard',1,1,'Why is guided media generally more secure than unguided media?','Signals are confined within physical cables.',1),
(970,1,1,'mcq','S2/SS1','Transmission Media',4,'hard',1,1,'Which medium is most flexible for temporary network setups?','Wireless (unguided) media is easier to deploy.',1),
(971,1,1,'mcq','S2/SS1','Transmission Media',4,'hard',1,1,'Why is fibre-optic installation more expensive than copper cables?','It requires specialized equipment and skills.',1),
(972,1,1,'mcq','S2/SS1','Transmission Media',4,'hard',1,1,'Which wireless technology is most suitable for connecting IoT devices in close proximity?','Bluetooth Low Energy is commonly used.',1),
(973,1,1,'mcq','S2/SS1','Transmission Media',4,'hard',1,1,'Why is satellite communication important for global broadcasting?','It covers very large geographic areas.',1),
(974,1,1,'mcq','S2/SS1','Transmission Media',4,'hard',1,1,'Which medium provides the lowest latency in local networks?','Guided cables provide faster direct transmission.',1),
(975,1,1,'mcq','S2/SS1','Transmission Media',4,'hard',1,1,'Why is Wi-Fi performance affected by walls and obstacles?','Signals weaken when passing through objects.',1),
(976,1,1,'mcq','S2/SS1','Transmission Media',4,'hard',1,1,'Which medium is most suitable for high-bandwidth video streaming across cities?','Fibre-optic cables support high bandwidth.',1),
(977,1,1,'mcq','S2/SS1','Transmission Media',4,'hard',1,1,'Why is twisted pair still widely used despite its limitations?','It is cost-effective and easy to install.',1),
(978,1,1,'mcq','S2/SS1','Transmission Media',4,'hard',1,1,'Which transmission medium is most vulnerable to weather conditions?','Wireless signals are affected by weather.',1),
(979,1,1,'mcq','S2/SS1','Transmission Media',4,'hard',1,1,'Why is NFC safer than Bluetooth for payments?','Its very short range reduces interception risk.',1),
(980,1,1,'mcq','S2/SS1','Transmission Media',4,'hard',1,1,'Which factor determines the bandwidth of a transmission medium?','The capacity to carry data signals.',1),
(981,1,1,'mcq','S2/SS1','Transmission Media',4,'hard',1,1,'Why are fibre-optic cables used in data centers?','They provide high speed and reliability.',1),
(982,1,1,'mcq','S2/SS1','Transmission Media',4,'hard',1,1,'Which technology is most suitable for connecting devices in a smart home?','Wi-Fi supports multiple devices easily.',1),
(983,1,1,'mcq','S2/SS1','Transmission Media',4,'hard',1,1,'Why is coaxial cable less flexible than twisted pair?','It has a thicker and rigid structure.',1),
(984,1,1,'mcq','S2/SS1','Transmission Media',4,'hard',1,1,'Which medium provides better performance in high-noise environments?','Fibre-optic performs best in noisy environments.',1),
(985,1,1,'mcq','S2/SS1','Transmission Media',4,'hard',1,1,'Why is unguided media ideal for mobile communication?','It allows movement without cables.',1),
(986,1,1,'mcq','S2/SS1','Transmission Media',4,'hard',1,1,'Which technology is most efficient for very short-range data exchange between devices?','NFC is ideal for very short range.',1),
(987,1,1,'mcq','S2/SS1','Transmission Media',4,'hard',1,1,'Why is fibre-optic cable difficult to tap into?','Signals are light-based and enclosed.',1),
(988,1,1,'mcq','S2/SS1','Transmission Media',4,'hard',1,1,'Which wireless medium provides the widest coverage?','Satellite communication covers the largest area.',1),
(989,1,1,'mcq','S2/SS1','Transmission Media',4,'hard',1,1,'Why is guided media less affected by environmental factors?','Signals are protected within cables.',1),
(990,1,1,'mcq','S2/SS1','Transmission Media',4,'hard',1,1,'Which medium is best for real-time communication with minimal delay?','Fibre-optic provides minimal delay.',1),
(991,1,1,'mcq','S2/SS1','Transmission Media',4,'hard',1,1,'Why is wireless communication more prone to interference than wired?','Signals travel through open air.',1),
(992,1,1,'mcq','S2/SS1','Transmission Media',4,'hard',1,1,'Which technology would best support communication in remote villages?','Satellite provides access where infrastructure is lacking.',1),
(993,1,1,'mcq','S2/SS1','Transmission Media',4,'hard',1,1,'Why is coaxial cable still used in cable TV networks?','It provides good signal quality over moderate distances.',1),
(994,1,1,'mcq','S2/SS1','Transmission Media',4,'hard',1,1,'Which medium is most scalable for future high-speed networks?','Fibre-optic supports future high bandwidth needs.',1);
